// Flux : Météo → Emails → Agenda → Format
let weatherNode = {};
try { weatherNode = $('Météo du jour').first().json; } catch(e) {}

const emailItems = $('Emails non lus').all();
const calendarItems = $input.all();

// Météo
let weatherSummary;
try {
  if (!weatherNode.main) {
    weatherSummary = 'Météo temporairement indisponible';
  } else {
    weatherSummary = `${weatherNode.weather[0].description}, ${Math.round(weatherNode.main.temp)}°C (ressenti ${Math.round(weatherNode.main.feels_like)}°C)`;
  }
} catch(e) {
  weatherSummary = 'Météo indisponible';
}

// Emails
let emailSummary = 'Emails non disponibles.';
let emailCount = 0;
try {
  const validEmails = emailItems.filter(e => e.json && !e.json.error);
  emailCount = validEmails.length;
  if (emailCount === 0) {
    emailSummary = 'Aucun email non lu.';
  } else {
    emailSummary = validEmails.map(e => {
      const d = e.json;
      const fromRaw = d.From || d.from || '';
      const from = fromRaw ? (fromRaw.includes('<') ? fromRaw.split('<')[0].trim() : fromRaw) : 'Inconnu';
      const snippet = d.snippet || d.bodyPreview || '';
      return `• ${from}: ${snippet.substring(0, 80)}...`;
    }).join('\n');
  }
} catch(e) {
  emailSummary = 'Erreur lecture emails: ' + e.message;
}

// Agenda
let calendarSummary = 'Agenda non disponible.';
let eventCount = 0;
try {
  const validEvents = calendarItems.filter(e => e.json && !e.json.error && e.json.summary);
  eventCount = validEvents.length;
  if (eventCount === 0) {
    calendarSummary = "Aucun événement aujourd'hui.";
  } else {
    calendarSummary = validEvents.map(e => {
      const ev = e.json;
      const title = ev.summary || 'Sans titre';
      const start = ev.start?.dateTime || ev.start?.date || '';
      let timeStr = '';
      if (start) {
        try {
          const d = new Date(start);
          timeStr = ev.start?.dateTime
            ? d.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' })
            : 'Journée entière';
        } catch(e) { timeStr = start; }
      }
      return `• ${timeStr ? timeStr + ' - ' : ''}${title}`;
    }).join('\n');
  }
} catch(e) {
  calendarSummary = 'Erreur lecture agenda: ' + e.message;
}

const now = new Date();
const greeting = now.getHours() < 12 ? 'Bonjour' : 'Bonsoir';
const dateStr = now.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' });

return [{ json: {
  briefing: `${greeting} Abo ! Nous sommes le ${dateStr}.\n\nMeteo : ${weatherSummary}.\n\nAgenda du jour (${eventCount} evenement(s)) :\n${calendarSummary}\n\nEmails importants :\n${emailSummary}`,
  weather: weatherSummary,
  email_count: emailCount,
  event_count: eventCount
}}];
